{{-- resources/views/user/profile.blade.php --}}
{{-- 用户资料页面 --}}

<x-layout.app 
    title="{{ $user->name . ' - 个人资料' }}"
    :showHeader="true"
    :showFooter="true">

    <div class="max-w-5xl mx-auto py-8 px-4 sm:px-6">
        
        {{-- 页面标题 --}}
        <div class="mb-8">
            <h1 class="text-3xl font-bold text-gray-900 dark:text-white">
                个人资料
            </h1>
            <p class="mt-2 text-gray-600 dark:text-gray-400">
                管理您的个人信息和账号设置
            </p>
        </div>

        {{-- 成功/错误消息 --}}
        @if (session('success'))
            <div x-data="{ show: true }" 
                 x-show="show"
                 x-transition
                 class="mb-6 p-4 bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 rounded-xl">
                <div class="flex items-center gap-3">
                    <svg class="w-5 h-5 text-green-600 dark:text-green-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"/>
                    </svg>
                    <p class="text-sm text-green-700 dark:text-green-300">{{ session('success') }}</p>
                    <button @click="show = false" class="ml-auto text-green-500 hover:text-green-700">
                        <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M6 18L18 6M6 6l12 12"/>
                        </svg>
                    </button>
                </div>
            </div>
        @endif

        <div class="grid grid-cols-1 lg:grid-cols-3 gap-6">
            
            {{-- 左侧：用户卡片 --}}
            <div class="lg:col-span-1">
                <div class="card p-6 sticky top-24">
                    {{-- 头像和信息 --}}
                    <div class="text-center">
                        <div class="relative inline-block">
                            <img src="{{ $user->avatar_url }}" alt="{{ $user->name }}"
                                class="w-28 h-28 rounded-full object-cover bg-gray-200 ring-4 ring-white dark:ring-gray-700">
                            @if($user->hasVerifiedEmail())
                                <span class="absolute bottom-1 right-1 w-6 h-6 bg-green-500 rounded-full flex items-center justify-center ring-2 ring-white dark:ring-gray-700" title="已验证邮箱">
                                    <svg class="w-3.5 h-3.5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="3" d="M5 13l4 4L19 7"/>
                                    </svg>
                                </span>
                            @endif
                        </div>
                        <h2 class="mt-4 text-xl font-bold text-gray-900 dark:text-white">{{ $user->name }}</h2>
                        <p class="text-sm text-gray-500 dark:text-gray-400 truncate px-4">{{ $user->email }}</p>
                        
                        {{-- 角色标签 --}}
                        <span class="inline-flex items-center px-3 py-1 mt-3 rounded-full text-xs font-medium
                            {{ $user->role->color() === 'red' ? 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-300' : '' }}
                            {{ $user->role->color() === 'blue' ? 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300' : '' }}
                            {{ $user->role->color() === 'gray' ? 'bg-gray-100 text-gray-800 dark:bg-gray-900/30 dark:text-gray-300' : '' }}">
                            {{ $user->role->label() }}
                        </span>
                    </div>

                    {{-- 统计数据 --}}
                    <div class="mt-6 pt-6 border-t border-gray-100 dark:border-gray-700">
                        <div class="grid grid-cols-3 gap-4 text-center">
                            <div>
                                <p class="text-2xl font-bold text-gray-900 dark:text-white">{{ $posts->total() }}</p>
                                <p class="text-xs text-gray-500 dark:text-gray-400">文章</p>
                            </div>
                            <div>
                                <p class="text-2xl font-bold text-gray-900 dark:text-white">{{ $user->comments()->count() }}</p>
                                <p class="text-xs text-gray-500 dark:text-gray-400">评论</p>
                            </div>
                            <div>
                                <p class="text-2xl font-bold text-gray-900 dark:text-white">{{ $user->followers()->count() }}</p>
                                <p class="text-xs text-gray-500 dark:text-gray-400">粉丝</p>
                            </div>
                        </div>
                    </div>

                    {{-- 社交链接 --}}
                    @if($user->social_links)
                        <div class="mt-6 pt-6 border-t border-gray-100 dark:border-gray-700">
                            <h3 class="text-sm font-medium text-gray-700 dark:text-gray-300 mb-3">社交链接</h3>
                            <div class="flex items-center justify-center gap-3">
                                @if(isset($user->social_links['github']))
                                    <a href="{{ $user->social_links['github'] }}" target="_blank" class="p-2 rounded-lg bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-600 transition-colors">
                                        <svg class="w-5 h-5" fill="currentColor" viewBox="0 0 24 24">
